// node_conv_196 — stem 7x7 conv2d, IC=3, OC=64, stride=2, padding=3.
// Tiled-streaming contract: input_width_bits=256, output_width_bits=256,
// channel_tile=32. Per the canonical ABI:
//   - IN_BEATS  = ceil(IC/32) = 1 beat per input pixel; data_in[23:0]
//     carries the IC=3 active channels (upper bits unused).
//   - OUT_BEATS = ceil(OC/32) = 2 beats per output pixel; beat 0 carries
//     channels 0..31 in data_out[255:0], beat 1 carries channels 32..63.
//
// Compute core is the standard split-architecture spatial conv
// (coord_scheduler + line_buf_window + conv_datapath). The inner datapath
// produces a registered OC*8 = 512-bit data_out vector with a 1-cycle
// valid_out pulse per output pixel; this wrapper splits that pulse into
// two consecutive 256-bit output beats. Beat 0 is forwarded
// combinationally on the SAME cycle as the inner valid_out, so the
// externally observed first valid_out fires at
// pipeline_latency_cycles = 10190. Beat 1 is held in a register and
// emitted on the next cycle with valid_out still asserted -- never
// dropped on the same cycle as its data.
module node_conv_196 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output wire              ready_in,
    input  wire [255:0]      data_in,
    output wire              valid_out,
    output wire [255:0]      data_out
);
    localparam integer IC        = 3;
    localparam integer OC        = 64;
    localparam integer IH        = 224;
    localparam integer IW        = 224;
    localparam integer OH        = 112;
    localparam integer OW        = 112;
    localparam integer KH        = 7;
    localparam integer KW        = 7;
    localparam integer SH        = 2;
    localparam integer SW        = 2;
    localparam integer PH        = 3;
    localparam integer PW        = 3;
    localparam integer K_TOTAL   = IC * KH * KW;
    localparam integer MP        = 4;
    localparam integer SCALE_MULT  = 11709;
    localparam integer SCALE_SHIFT = 23;

    reg started, start_pulse, pending_rearm;
    wire sched_out_frame_done;
    wire                              sched_needs_real_input;
    wire                              sched_ready_in;
    wire                              sched_output_fires;
    wire                              sched_advance;
    wire [$clog2(IH + PH + 1)-1:0]    sched_in_row;
    wire [$clog2(IW + PW + 1)-1:0]    sched_in_col;
    wire [$clog2(OH * OW + 1)-1:0]    sched_outputs_emitted;
    wire [KH*KW*IC*8-1:0]             window_flat;
    wire                              mac_busy;
    wire                              inner_valid_out;
    wire [OC*8-1:0]                   inner_data_out;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            started <= 1'b0; start_pulse <= 1'b0; pending_rearm <= 1'b0;
        end else begin
            start_pulse <= 1'b0;
            if (sched_out_frame_done) pending_rearm <= 1'b1;
            if (!started) begin started <= 1'b1; start_pulse <= 1'b1; end
            else if (pending_rearm && !mac_busy) begin started <= 1'b0; pending_rearm <= 1'b0; end
        end
    end

    wire stall_in = mac_busy;

    coord_scheduler #(.IH(IH),.IW(IW),.OH(OH),.OW(OW),.KH(KH),.KW(KW),.SH(SH),.SW(SW),.PH(PH),.PW(PW)) scheduler (
        .clk(clk),.rst_n(rst_n),.start(start_pulse),.stall_in(stall_in),.valid_in(valid_in),.ready_in(sched_ready_in),
        .needs_real_input(sched_needs_real_input),.in_row(sched_in_row),.in_col(sched_in_col),
        .output_fires(sched_output_fires),.advance(sched_advance),.in_frame_done(),
        .out_frame_done(sched_out_frame_done),.outputs_emitted(sched_outputs_emitted));

    line_buf_window #(.IC(IC),.IW(IW),.IH(IH),.KH(KH),.KW(KW),.PW(PW),.PH(PH)) lbw (
        .clk(clk),.rst_n(rst_n),.frame_start(start_pulse),.sched_in_row(sched_in_row),.sched_in_col(sched_in_col),
        .sched_needs_real_input(sched_needs_real_input),.sched_advance(sched_advance),
        .sched_output_fires(sched_output_fires),.valid_in(valid_in),.data_in(data_in[IC*8-1:0]),.window_flat(window_flat));

    conv_datapath #(.IC(IC),.OC(OC),.KH(KH),.KW(KW),.K_TOTAL(K_TOTAL),.MP(MP),.SCALE_MULT(SCALE_MULT),.SCALE_SHIFT(SCALE_SHIFT),
        .WEIGHTS_PATH("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_196_weights.hex"),
        .BIAS_PATH("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_196_bias.hex")) dp (
        .clk(clk),.rst_n(rst_n),.window_flat(window_flat),.start_mac(sched_output_fires),
        .valid_out(inner_valid_out),.data_out(inner_data_out),.mac_busy(mac_busy));

    reg [255:0] held_beat1;
    reg         emit_beat1;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin held_beat1 <= 256'd0; emit_beat1 <= 1'b0; end
        else if (inner_valid_out) begin held_beat1 <= inner_data_out[OC*8-1:256]; emit_beat1 <= 1'b1; end
        else emit_beat1 <= 1'b0;
    end
    assign valid_out = inner_valid_out | emit_beat1;
    assign data_out  = emit_beat1 ? held_beat1 : inner_data_out[255:0];
    assign ready_in  = sched_ready_in;
endmodule
